<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<meta name="theme-color" content="#0a0a1a">
<title>Multiverse Observatory — Parallel Universe Simulations</title>
<script src="https://cdn.tailwindcss.com"></script>
<script src="https://cdn.jsdelivr.net/npm/chart.js@4.4.7/dist/chart.umd.min.js"></script>
<link href="https://fonts.googleapis.com/css2?family=Orbitron:wght@400;700;900&family=Inter:wght@300;400;500;600&display=swap" rel="stylesheet">
<style>
  :root {
    --bg-primary: #07071a;
    --bg-secondary: #0d0d2b;
    --accent-cyan: #00e5ff;
    --accent-magenta: #e040fb;
    --accent-amber: #ffab40;
    --accent-green: #69f0ae;
    --glass: rgba(12, 12, 40, 0.65);
    --glass-border: rgba(0, 229, 255, 0.12);
    --text-primary: #e8eaf0;
    --text-muted: rgba(255,255,255,0.45);
  }

  *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

  html { height: 100%; }

  body {
    height: 100%;
    background: var(--bg-primary);
    font-family: 'Inter', sans-serif;
    color: var(--text-primary);
    overflow: hidden;
  }

  @media (max-width: 1023px) {
    body { overflow-y: auto; overflow-x: hidden; }
  }

  .font-orbitron { font-family: 'Orbitron', monospace; }

  /* Star Canvas */
  #starCanvas {
    position: fixed;
    inset: 0;
    z-index: 0;
    pointer-events: none;
    width: 100%;
    height: 100%;
  }

  /* Nebulae */
  .nebula {
    position: fixed;
    border-radius: 50%;
    filter: blur(90px);
    opacity: 0.14;
    pointer-events: none;
    z-index: 0;
  }

  /* Holographic grid overlay */
  .grid-overlay {
    position: fixed;
    inset: 0;
    z-index: 0;
    pointer-events: none;
    background-image:
      linear-gradient(rgba(0,229,255,0.018) 1px, transparent 1px),
      linear-gradient(90deg, rgba(0,229,255,0.018) 1px, transparent 1px);
    background-size: 40px 40px;
  }

  /* Glass Panel — enhanced */
  .glass-panel {
    background: var(--glass);
    backdrop-filter: blur(20px);
    -webkit-backdrop-filter: blur(20px);
    border: 1px solid var(--glass-border);
    border-radius: 14px;
    transition: border-color 0.35s ease, box-shadow 0.35s ease;
  }
  .glass-panel:hover {
    border-color: rgba(0, 229, 255, 0.28);
    box-shadow: 0 0 30px rgba(0, 229, 255, 0.06);
  }

  /* Section title accent bar */
  .section-title {
    display: flex;
    align-items: center;
    gap: 8px;
    margin-bottom: 10px;
  }
  .section-title::before {
    content: '';
    display: inline-block;
    width: 3px;
    height: 14px;
    border-radius: 2px;
    background: var(--accent-cyan);
    flex-shrink: 0;
  }

  .glow-cyan { text-shadow: 0 0 14px rgba(0, 229, 255, 0.5); }
  .glow-magenta { text-shadow: 0 0 14px rgba(224, 64, 251, 0.5); }

  /* Buttons — enhanced */
  .btn-cosmic {
    background: linear-gradient(135deg, rgba(0,229,255,0.12), rgba(224,64,251,0.12));
    border: 1px solid rgba(0,229,255,0.25);
    color: var(--accent-cyan);
    padding: 6px 18px;
    border-radius: 8px;
    font-size: 0.75rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s ease;
    font-family: 'Inter', sans-serif;
    letter-spacing: 0.04em;
    outline: none;
    position: relative;
    overflow: hidden;
  }
  .btn-cosmic::after {
    content: '';
    position: absolute;
    inset: 0;
    background: linear-gradient(135deg, rgba(0,229,255,0.08), transparent);
    opacity: 0;
    transition: opacity 0.3s;
  }
  .btn-cosmic:hover {
    background: linear-gradient(135deg, rgba(0,229,255,0.28), rgba(224,64,251,0.28));
    border-color: var(--accent-cyan);
    box-shadow: 0 0 24px rgba(0,229,255,0.18), inset 0 0 12px rgba(0,229,255,0.05);
    transform: translateY(-1px);
  }
  .btn-cosmic:hover::after { opacity: 1; }
  .btn-cosmic:active { transform: translateY(0); }
  .btn-cosmic:focus-visible {
    outline: 2px solid var(--accent-cyan);
    outline-offset: 2px;
  }
  .btn-cosmic.active-btn {
    background: linear-gradient(135deg, rgba(0,229,255,0.22), rgba(224,64,251,0.18));
    border-color: var(--accent-cyan);
    color: #ffffff;
    box-shadow: 0 0 16px rgba(0,229,255,0.12);
  }

  .indicator-dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    animation: pulse-dot 2s ease-in-out infinite;
    flex-shrink: 0;
  }
  @keyframes pulse-dot {
    0%, 100% { opacity: 0.55; box-shadow: 0 0 4px currentColor; }
    50% { opacity: 1; box-shadow: 0 0 14px currentColor; }
  }

  /* Scrollbar */
  .scroll-thin::-webkit-scrollbar { width: 4px; }
  .scroll-thin::-webkit-scrollbar-track { background: transparent; }
  .scroll-thin::-webkit-scrollbar-thumb { background: rgba(0,229,255,0.18); border-radius: 2px; }
  .scroll-thin::-webkit-scrollbar-thumb:hover { background: rgba(0,229,255,0.35); }

  /* Convergence bar */
  .convergence-bar {
    height: 4px;
    border-radius: 2px;
    background: rgba(255,255,255,0.06);
    overflow: hidden;
  }
  .convergence-fill {
    height: 100%;
    border-radius: 2px;
    transition: width 0.8s cubic-bezier(0.4, 0, 0.2, 1);
  }

  /* Universe card */
  .universe-card {
    cursor: pointer;
    transition: all 0.3s ease;
    position: relative;
  }
  .universe-card:hover {
    transform: scale(1.025);
    border-color: rgba(0,229,255,0.4) !important;
  }
  .universe-card.selected {
    border-color: var(--accent-cyan) !important;
    box-shadow: 0 0 20px rgba(0,229,255,0.12), inset 0 0 20px rgba(0,229,255,0.03);
  }
  .universe-card:focus-visible {
    outline: 2px solid var(--accent-cyan);
    outline-offset: 2px;
  }

  /* Scanline — refined */
  .scanline-effect { position: relative; overflow: hidden; }
  .scanline-effect::after {
    content: '';
    position: absolute;
    left: 0;
    width: 100%;
    height: 2px;
    background: linear-gradient(90deg, transparent, rgba(0,229,255,0.1), transparent);
    animation: scanline 8s linear infinite;
    pointer-events: none;
    z-index: 2;
  }
  @keyframes scanline {
    0% { top: -2px; }
    100% { top: 100%; }
  }

  /* Inputs — enhanced contrast */
  .input-cosmic {
    width: 100%;
    padding: 8px 14px;
    border-radius: 8px;
    font-size: 0.8rem;
    background: rgba(255,255,255,0.04);
    border: 1px solid rgba(0,229,255,0.18);
    color: var(--text-primary);
    outline: none;
    font-family: 'Inter', sans-serif;
    transition: border-color 0.3s, box-shadow 0.3s, background 0.3s;
  }
  .input-cosmic::placeholder { color: rgba(255,255,255,0.28); }
  .input-cosmic:focus {
    border-color: var(--accent-cyan);
    box-shadow: 0 0 16px rgba(0,229,255,0.12);
    background: rgba(0,229,255,0.04);
  }
  .input-cosmic:focus-visible {
    outline: none;
    border-color: var(--accent-cyan);
    box-shadow: 0 0 16px rgba(0,229,255,0.15);
  }

  /* Modal */
  .modal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,0.72);
    backdrop-filter: blur(6px);
    z-index: 100;
    display: flex;
    align-items: center;
    justify-content: center;
    opacity: 0;
    pointer-events: none;
    transition: opacity 0.3s;
  }
  .modal-overlay.active { opacity: 1; pointer-events: all; }
  .modal-box { transform: scale(0.92) translateY(10px); transition: transform 0.35s cubic-bezier(0.4,0,0.2,1); }
  .modal-overlay.active .modal-box { transform: scale(1) translateY(0); }

  /* Float animation */
  @keyframes float {
    0%, 100% { transform: translateY(0); }
    50% { transform: translateY(-5px); }
  }
  .float-anim { animation: float 4s ease-in-out infinite; }

  /* Toast */
  @keyframes fadeInOut {
    0% { opacity: 0; transform: translateY(-12px) scale(0.95); }
    12% { opacity: 1; transform: translateY(0) scale(1); }
    82% { opacity: 1; transform: translateY(0) scale(1); }
    100% { opacity: 0; transform: translateY(-12px) scale(0.95); }
  }

  /* Metric card glow */
  .metric-card {
    text-align: center;
    padding: 10px 8px;
    border-radius: 10px;
    transition: background 0.3s;
    position: relative;
    overflow: hidden;
  }
  .metric-card::after {
    content: '';
    position: absolute;
    inset: 0;
    border-radius: 10px;
    opacity: 0;
    transition: opacity 0.3s;
  }
  .metric-card:hover::after { opacity: 1; }

  /* Expert quote card */
  .expert-card {
    display: flex;
    gap: 10px;
    padding: 10px;
    border-radius: 10px;
    background: rgba(255,255,255,0.02);
    border: 1px solid rgba(255,255,255,0.04);
    transition: border-color 0.3s, background 0.3s;
  }
  .expert-card:hover {
    border-color: rgba(0,229,255,0.15);
    background: rgba(0,229,255,0.03);
  }

  /* Discussion item */
  .discussion-item {
    display: flex;
    gap: 10px;
    padding: 8px 0;
    border-bottom: 1px solid rgba(255,255,255,0.04);
  }
  .discussion-item:last-child { border-bottom: none; }

  .avatar-circle {
    width: 28px;
    height: 28px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 0.65rem;
    font-weight: 700;
    flex-shrink: 0;
  }

  /* Select styling */
  select.input-cosmic {
    appearance: none;
    background-image: url("data:image/svg+xml,%3Csvg width='12' height='8' viewBox='0 0 12 8' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M1 1.5L6 6.5L11 1.5' stroke='rgba(0,229,255,0.5)' stroke-width='1.5' stroke-linecap='round'/%3E%3C/svg%3E");
    background-repeat: no-repeat;
    background-position: right 12px center;
    padding-right: 32px;
  }

  /* Responsive adjustments */
  @media (max-width: 1023px) {
    .main-layout { height: auto !important; min-height: 100vh; overflow-y: auto; }
    .main-grid { height: auto !important; }
  }

  /* Reduced motion */
  @media (prefers-reduced-motion: reduce) {
    *, *::before, *::after {
      animation-duration: 0.01ms !important;
      animation-iteration-count: 1 !important;
      transition-duration: 0.01ms !important;
    }
  }
</style>
</head>
<body class="relative">

<!-- Canvas Star Field -->
<canvas id="starCanvas" aria-hidden="true"></canvas>

<!-- Nebula Backgrounds -->
<div class="nebula" style="width:550px;height:550px;background:radial-gradient(circle,rgba(0,229,255,0.35),transparent);top:-120px;left:-120px;" aria-hidden="true"></div>
<div class="nebula" style="width:650px;height:650px;background:radial-gradient(circle,rgba(224,64,251,0.28),transparent);bottom:-160px;right:-160px;" aria-hidden="true"></div>
<div class="nebula" style="width:380px;height:380px;background:radial-gradient(circle,rgba(255,171,64,0.18),transparent);top:38%;left:48%;" aria-hidden="true"></div>

<!-- Holographic Grid -->
<div class="grid-overlay" aria-hidden="true"></div>

<!-- Main Layout -->
<div class="relative z-10 h-full flex flex-col p-3 gap-2.5 main-layout" style="max-height:100vh;">

  <!-- Header -->
  <header class="flex items-center justify-between px-5 py-3 glass-panel" style="flex-shrink:0;" role="banner">
    <div class="flex items-center gap-3.5">
      <div class="relative w-10 h-10 flex items-center justify-center">
        <svg width="40" height="40" viewBox="0 0 40 40" class="float-anim" aria-hidden="true">
          <circle cx="20" cy="20" r="16" fill="none" stroke="rgba(0,229,255,0.25)" stroke-width="1"/>
          <ellipse cx="20" cy="20" rx="16" ry="7" fill="none" stroke="rgba(0,229,255,0.55)" stroke-width="1.2" transform="rotate(-30 20 20)"/>
          <ellipse cx="20" cy="20" rx="16" ry="7" fill="none" stroke="rgba(224,64,251,0.45)" stroke-width="1.2" transform="rotate(30 20 20)"/>
          <ellipse cx="20" cy="20" rx="16" ry="7" fill="none" stroke="rgba(105,240,174,0.3)" stroke-width="0.8" transform="rotate(90 20 20)"/>
          <circle cx="20" cy="20" r="3.5" fill="var(--accent-cyan)" opacity="0.85"/>
        </svg>
      </div>
      <div>
        <h1 class="font-orbitron text-sm font-bold tracking-widest glow-cyan" style="color:var(--accent-cyan);">MULTIVERSE OBSERVATORY</h1>
        <p class="text-xs opacity-45 tracking-wide mt-0.5">Parallel Universe Simulation Engine v4.2</p>
      </div>
    </div>
    <div class="flex items-center gap-4">
      <div class="flex items-center gap-2 text-xs opacity-60">
        <div class="indicator-dot" style="background:var(--accent-green);color:var(--accent-green);"></div>
        <span id="realitiesOnlineLabel">7 Realities Online</span>
      </div>
      <button class="btn-cosmic hidden md:inline-flex items-center" onclick="openModal('propose')" aria-label="Propose a new universe">
        + Propose Universe
      </button>
      <div class="w-8 h-8 rounded-full flex items-center justify-center cursor-pointer" style="background:linear-gradient(135deg,var(--accent-cyan),var(--accent-magenta));" title="User Profile" role="button" aria-label="User Profile">
        <span class="text-xs font-bold text-black">OB</span>
      </div>
    </div>
  </header>

  <!-- Main Content Grid -->
  <div class="flex-1 grid grid-cols-12 gap-2.5 min-h-0 main-grid">

    <!-- Left Panel: Universe Selector -->
    <aside class="col-span-12 lg:col-span-2 glass-panel p-3.5 flex flex-col gap-2 overflow-y-auto scroll-thin" role="navigation" aria-label="Universe selector">
      <div class="section-title">
        <h2 class="font-orbitron text-xs font-bold tracking-wider opacity-75">REALITIES</h2>
      </div>
      <div id="universeList" class="flex flex-col gap-2.5"></div>
    </aside>

    <!-- Center: Main Chart Area -->
    <main class="col-span-12 lg:col-span-7 flex flex-col gap-2.5 min-h-0" role="main">
      <!-- Chart Panel -->
      <div class="glass-panel p-5 flex-1 relative scanline-effect min-h-0 flex flex-col">
        <div class="flex items-center justify-between mb-3" style="flex-shrink:0;">
          <div>
            <div class="section-title" style="margin-bottom:4px;">
              <h2 class="font-orbitron text-xs font-bold tracking-wider glow-cyan" style="color:var(--accent-cyan);">DIVERGENCE SIMULATION</h2>
            </div>
            <p class="text-xs opacity-40 ml-3">Comparative timeline analysis across selected realities</p>
          </div>
          <div class="flex gap-1.5" role="tablist" aria-label="Chart type selection">
            <button class="btn-cosmic text-xs px-3 py-1.5 active-btn" onclick="setChartType('line')" id="btnLine" role="tab" aria-selected="true" aria-label="Timeline view">Timeline</button>
            <button class="btn-cosmic text-xs px-3 py-1.5" onclick="setChartType('radar')" id="btnRadar" role="tab" aria-selected="false" aria-label="Spectrum view">Spectrum</button>
            <button class="btn-cosmic text-xs px-3 py-1.5" onclick="setChartType('bar')" id="btnBar" role="tab" aria-selected="false" aria-label="Comparison view">Comparison</button>
          </div>
        </div>
        <div class="flex-1 relative min-h-0" style="min-height:160px;">
          <canvas id="mainChart" aria-label="Divergence simulation chart"></canvas>
        </div>
      </div>

      <!-- Bottom Row -->
      <div class="grid grid-cols-1 md:grid-cols-2 gap-2.5" style="flex-shrink:0; min-height:190px;">
        <!-- Probability Chart -->
        <div class="glass-panel p-4 flex flex-col">
          <div class="section-title" style="margin-bottom:6px;">
            <h3 class="font-orbitron text-xs font-bold tracking-wider opacity-75">CONVERGENCE PROBABILITY</h3>
          </div>
          <div class="flex-1 relative min-h-0" style="min-height:80px;">
            <canvas id="probChart" aria-label="Convergence probability chart"></canvas>
          </div>
        </div>
        <!-- Expert Insights -->
        <div class="glass-panel p-4 flex flex-col overflow-hidden">
          <div class="section-title" style="margin-bottom:6px;">
            <h3 class="font-orbitron text-xs font-bold tracking-wider opacity-75">EXPERT INSIGHTS</h3>
          </div>
          <div class="flex-1 overflow-y-auto scroll-thin flex flex-col gap-2.5" id="expertList" aria-label="Expert insights"></div>
        </div>
      </div>
    </main>

    <!-- Right Panel -->
    <aside class="col-span-12 lg:col-span-3 flex flex-col gap-2.5 min-h-0">
      <!-- Stats -->
      <div class="glass-panel p-4" style="flex-shrink:0;">
        <div class="section-title" style="margin-bottom:12px;">
          <h3 class="font-orbitron text-xs font-bold tracking-wider opacity-75">SIMULATION METRICS</h3>
        </div>
        <div class="grid grid-cols-2 gap-2.5">
          <div class="metric-card" style="background:rgba(0,229,255,0.06);">
            <div class="text-xl font-bold font-orbitron glow-cyan" style="color:var(--accent-cyan);" id="metricRealities">7</div>
            <div class="text-xs opacity-40 mt-1">Realities</div>
          </div>
          <div class="metric-card" style="background:rgba(224,64,251,0.06);">
            <div class="text-xl font-bold font-orbitron glow-magenta" style="color:var(--accent-magenta);" id="metricDivergence">23.4%</div>
            <div class="text-xs opacity-40 mt-1">Avg Divergence</div>
          </div>
          <div class="metric-card" style="background:rgba(105,240,174,0.06);">
            <div class="text-xl font-bold font-orbitron" style="color:var(--accent-green);" id="metricStability">89%</div>
            <div class="text-xs opacity-40 mt-1">Stability</div>
          </div>
          <div class="metric-card" style="background:rgba(255,171,64,0.06);">
            <div class="text-xl font-bold font-orbitron" style="color:var(--accent-amber);" id="metricEvents">142</div>
            <div class="text-xs opacity-40 mt-1">Branch Events</div>
          </div>
        </div>
      </div>

      <!-- Discussion / Theories -->
      <div class="glass-panel p-4 flex-1 flex flex-col min-h-0 overflow-hidden">
        <div class="flex items-center justify-between mb-3" style="flex-shrink:0;">
          <div class="section-title" style="margin-bottom:0;">
            <h3 class="font-orbitron text-xs font-bold tracking-wider opacity-75">MULTIVERSE DISCUSSION</h3>
          </div>
          <span class="text-xs opacity-35">12 online</span>
        </div>
        <div class="flex-1 overflow-y-auto scroll-thin flex flex-col gap-1" id="discussionList" aria-live="polite" aria-label="Discussion messages"></div>
        <div class="mt-3 flex gap-2" style="flex-shrink:0;">
          <input id="chatInput" type="text" placeholder="Share a theory..." class="input-cosmic flex-1" style="padding:8px 14px;font-size:0.78rem;" onkeydown="if(event.key==='Enter')sendChat()" aria-label="Type your theory">
          <button class="btn-cosmic px-4 py-2" onclick="sendChat()" aria-label="Send message">→</button>
        </div>
      </div>
    </aside>
  </div>

  <!-- Footer -->
  <footer class="flex items-center justify-between px-5 py-2 glass-panel text-xs opacity-40" style="flex-shrink:0;" role="contentinfo">
    <span>© 2025 Multiverse Observatory — Quantum Data Division</span>
    <div class="flex gap-5">
      <span class="cursor-pointer hover:opacity-80 transition-opacity" tabindex="0">Methodology</span>
      <span class="cursor-pointer hover:opacity-80 transition-opacity" tabindex="0">API</span>
      <span class="cursor-pointer hover:opacity-80 transition-opacity" tabindex="0">Paper</span>
    </div>
  </footer>
</div>

<!-- Propose Universe Modal -->
<div class="modal-overlay" id="proposeModal" role="dialog" aria-modal="true" aria-labelledby="proposeModalTitle">
  <div class="modal-box glass-panel p-7 w-full max-w-md mx-4">
    <h2 id="proposeModalTitle" class="font-orbitron text-sm font-bold tracking-wider glow-cyan mb-5" style="color:var(--accent-cyan);">PROPOSE A UNIVERSE</h2>
    <div class="flex flex-col gap-4">
      <div>
        <label class="text-xs opacity-55 block mb-1.5 font-medium" for="newUniverseName">Universe Designation</label>
        <input id="newUniverseName" type="text" placeholder="e.g. U-Ω-09" class="input-cosmic">
      </div>
      <div>
        <label class="text-xs opacity-55 block mb-1.5 font-medium" for="newDivergenceYear">Divergence Point (Year)</label>
        <input id="newDivergenceYear" type="number" value="1962" class="input-cosmic">
      </div>
      <div>
        <label class="text-xs opacity-55 block mb-1.5 font-medium" for="newDivergenceFactor">Key Divergence Factor</label>
        <select id="newDivergenceFactor" class="input-cosmic">
          <option value="political">Political Event</option>
          <option value="scientific">Scientific Discovery</option>
          <option value="catastrophe">Global Catastrophe</option>
          <option value="technological">Technological Breakthrough</option>
          <option value="cultural">Cultural Shift</option>
        </select>
      </div>
      <div>
        <label class="text-xs opacity-55 block mb-1.5 font-medium" for="newUniverseDesc">Description</label>
        <textarea id="newUniverseDesc" rows="2" placeholder="Describe this alternate reality..." class="input-cosmic" style="resize:none;"></textarea>
      </div>
      <!-- Live preview metrics -->
      <div class="flex gap-3 p-3 rounded-lg" style="background:rgba(0,229,255,0.04);border:1px solid rgba(0,229,255,0.08);">
        <div class="flex-1 text-center">
          <div class="text-xs opacity-40 mb-1">Est. Stability</div>
          <div class="font-orbitron text-sm font-bold" style="color:var(--accent-green);" id="previewStability">--</div>
        </div>
        <div class="w-px" style="background:rgba(255,255,255,0.06);"></div>
        <div class="flex-1 text-center">
          <div class="text-xs opacity-40 mb-1">Est. Divergence</div>
          <div class="font-orbitron text-sm font-bold" style="color:var(--accent-magenta);" id="previewDivergence">--</div>
        </div>
      </div>
