(function initStarField() {
  const canvas = document.getElementById('starCanvas');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  if (!ctx) return;

  let stars = [];
  let mouseX = 0, mouseY = 0;
  let animId = null;

  function resize() {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    createStars();
  }

  function createStars() {
    const count = Math.min(180, Math.floor((canvas.width * canvas.height) / 8000));
    stars = Array.from({ length: count }, () => ({
      x: Math.random() * canvas.width,
      y: Math.random() * canvas.height,
      size: Math.random() * 1.8 + 0.4,
      speed: Math.random() * 0.6 + 0.15,
      phase: Math.random() * Math.PI * 2,
      brightness: 0.3 + Math.random() * 0.7
    }));
  }

  function animate(time) {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    const parallaxScale = 0.008;

    for (let i = 0; i < stars.length; i++) {
      const s = stars[i];
      const twinkle = 0.3 + 0.7 * (0.5 + 0.5 * Math.sin(time * 0.001 * s.speed + s.phase));
      const alpha = twinkle * s.brightness;
      const px = s.x + mouseX * parallaxScale * s.size;
      const py = s.y + mouseY * parallaxScale * s.size;

      ctx.beginPath();
      ctx.arc(px, py, Math.max(0.3, s.size), 0, Math.PI * 2);
      ctx.fillStyle = `rgba(220,235,255,${alpha.toFixed(3)})`;
      ctx.fill();

      // Subtle glow for larger stars
      if (s.size > 1.4) {
        ctx.beginPath();
        ctx.arc(px, py, s.size * 2.5, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(180,220,255,${(alpha * 0.08).toFixed(3)})`;
        ctx.fill();
      }
    }

    animId = requestAnimationFrame(animate);
  }

  document.addEventListener('mousemove', (e) => {
    mouseX = (e.clientX / window.innerWidth - 0.5) * 2;
    mouseY = (e.clientY / window.innerHeight - 0.5) * 2;
  });

  window.addEventListener('resize', resize);
  resize();

  // Respect reduced motion
  const motionQuery = window.matchMedia('(prefers-reduced-motion: reduce)');
  if (!motionQuery.matches) {
    animId = requestAnimationFrame(animate);
  } else {
    // Draw static frame
    animate(0);
  }
  motionQuery.addEventListener('change', (e) => {
    if (e.matches && animId) {
      cancelAnimationFrame(animId);
    } else {
      animId = requestAnimationFrame(animate);
    }
  });
})();

