  const toast = document.createElement('div');
  toast.className = 'fixed top-4 right-4 z-50 glass-panel px-5 py-3 text-xs font-orbitron tracking-wider';
  toast.style.cssText = 'color:var(--accent-cyan);border-color:rgba(0,229,255,0.4);animation:fadeInOut 3s forwards;pointer-events:none;';
  toast.textContent = msg;
  toast.setAttribute('role', 'alert');
  document.body.appendChild(toast);
  setTimeout(() => { if (toast.parentNode) toast.remove(); }, 3200);
}

// ======================== STATE SUBSCRIBERS ========================
State.subscribe(() => {
  renderUniverseList();
  refreshMainChartData();
  refreshProbChartData();
  updateMetrics();
});

// Chart type changes need rebuild
const originalSetChartType = State.setChartType.bind(State);
State.setChartType = function(type) {
  if (this.currentChartType === type) return;
  this.currentChartType = type;

  // Update button states
  ['btnLine', 'btnRadar', 'btnBar'].forEach(id => {
    const btn = document.getElementById(id);
    if (btn) {
      btn.classList.remove('active-btn');
      btn.setAttribute('aria-selected', 'false');
    }
  });
  const btnMap = { line: 'btnLine', radar: 'btnRadar', bar: 'btnBar' };
  const activeBtn = document.getElementById(btnMap[type]);
  if (activeBtn) {
    activeBtn.classList.add('active-btn');
    activeBtn.setAttribute('aria-selected', 'true');
  }

  // Type change requires full rebuild
  rebuildMainChart();
};

// ======================== INITIALIZATION ========================
document.addEventListener('DOMContentLoaded', () => {
  renderUniverseList();
  createMainChart();
  createProbChart();
  renderExperts();
  renderDiscussions();
  updateMetrics();

  // Animate convergence bars on load
  setTimeout(() => {
    document.querySelectorAll('.convergence-fill').forEach(el => {
      const w = el.style.width;
      el.style.width = '0%';
      requestAnimationFrame(() => {
        requestAnimationFrame(() => { el.style.width = w; });
      });
    });
  }, 200);

  // Close modal on overlay click
  const proposeModal = document.getElementById('proposeModal');
  if (proposeModal) {
    proposeModal.addEventListener('click', function(e) {
      if (e.target === this) closeModal('propose');
    });
  }

  // Close modal on Escape
  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') {
      const activeModal = document.querySelector('.modal-overlay.active');
      if (activeModal) {
        const id = activeModal.id.replace('Modal', '');
        closeModal(id);
      }
    }
  });

  // Live preview on factor change
  const factorSelect = document.getElementById('newDivergenceFactor');
  if (factorSelect) {
    factorSelect.addEventListener('change', updatePreviewMetrics);
  }
});
</script>

